          <p class="status-text" :class="{ 'ready': isReady }">
            {{ loadingStatus }}
          </p>
          <div v-if="!isReady" class="progress-bar">
            <div class="progress-fill"></div>
          </div>
        </div>

        <transition name="slide-up">
          <button v-if="isReady" class="btn-primary" @click="$emit('enter')">
            ΕΙΣΟΔΟΣ ΣΤΟ ΜΑΝΤΕΙΟ
          </button>
