</template>
<style lang="scss" src="@/assets/scss/SplashView.scss" scoped></style>

<script setup>
import { ref, shallowRef, onMounted } from 'vue';
import * as tf from '@tensorflow/tfjs';
import { gsap } from 'gsap';
import { MorphSVGPlugin } from 'gsap/MorphSVGPlugin';

const model = shallowRef(null);
const emit = defineEmits(['ready', 'enter']);
const loadingStatus = ref('Προετοιμασια...');
const isReady = ref(false);

defineProps(['status', 'isReady']);

onMounted(async() => {
  gsap.registerPlugin(MorphSVGPlugin);

  setTimeout(() => {
    gsap.to("#XB", { morphSVG: "#X", duration: 1, yoyo: false });
    gsap.to("#SB", { morphSVG: "#S", duration: 1, yoyo: false });
    gsap.to("#IB", { morphSVG: "#I", duration: 1, yoyo: false });
    gsap.to("#Y1B", { morphSVG: "#Y1", duration: 1, yoyo: false });
  }, 1500);

  setTimeout(() => {
    gsap.to("#RB", { morphSVG: "#R", duration: 1, yoyo: false });
    gsap.to("#O1B", { morphSVG: "#O1", duration: 1, yoyo: false });
    gsap.to("#HB", { morphSVG: "#H", duration: 1, yoyo: false });
    gsap.to("#Y3B", { morphSVG: "#Y3", duration: 1, yoyo: false });
    gsap.to("#M2B", { morphSVG: "#M2", duration: 1, yoyo: false });
  }, 2000);

  setTimeout(() => {
    gsap.to("#M1B", { morphSVG: "#M1", duration: 1, yoyo: false });
    gsap.to("#O2B", { morphSVG: "#O2", duration: 1, yoyo: false });
    gsap.to("#TB", { morphSVG: "#T", duration: 1, yoyo: false });
    gsap.to("#Y2B", { morphSVG: "#Y2", duration: 1, yoyo: false });
  }, 2500);

  setTimeout(() => {
    gsap.to("#O3B", { morphSVG: "#O3", duration: 1, yoyo: false });
    gsap.to("#O4B", { morphSVG: "#O4", duration: 1, yoyo: false });
  }, 3000);

  setTimeout(() => {
    gsap.to("#LB", { morphSVG: "#L", duration: 1, yoyo: false });
    gsap.to("#PB", { morphSVG: "#P", duration: 1, yoyo: false });
  }, 3500);
  try {
      await tf.ready();
      tf.env().set('WEBGL_PACK', false);
      loadingStatus.value = 'Οι Ιεροφαντες ετοιμαζονται...';
      const loadedModel = await tf.loadGraphModel('./model/rune_model_v102.json');
      model.value = loadedModel; // Local reference if needed
      emit('ready', loadedModel);
      loadingStatus.value = 'Το Μαντειο ειναι ετοιμο';
      isReady.value = true;
    } catch (e) {
      loadingStatus.value = 'Οι οιωνοι δεν είναι ευνοϊκοι. Το Μαντειο ειναι κλειστο.';
      console.error(e);
    }
});
</script>
